files.flake.nix:
{
  description = "mofaflex - Factor Analysis Models";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        python = pkgs.python311;
        coreScope = { inherit (pkgs) lib fetchPypi; };
        customPackages = let
          callPackageWith = pkgs.lib.callPackageWith;
          pythonPackageScope = python.pkgs // customPackages // coreScope;
        in rec {
          mudata = callPackageWith pythonPackageScope ./mudata { };
          mofaflex = callPackageWith pythonPackageScope ./mofaflex { };
          main = mofaflex;
        };
      in {
        packages = customPackages // {
          default = customPackages.mofaflex;
        };
      }
    );
}

files.mofaflex/default.nix:
{
  lib,
  buildPythonPackage,
  fetchPypi,
  hatchling,
  pythonOlder,
  anndata,
  array-api-compat,
  dtw-python,
  gpytorch,
  h5py,
  mizani,
  mudata,
  numpy,
  packaging,
  pandas,
  platformdirs,
  plotnine,
  pyro-ppl,
  scikit-learn,
  scipy,
  session-info2,
  statsmodels,
  torch,
  tqdm,
}:

buildPythonPackage rec {
  pname = "mofaflex";
  version = "0.1.0.post1";
  pyproject = true;

  disabled = pythonOlder "3.11";

  src = fetchPypi {
    inherit pname version;
    hash = lib.fakeSha256;
  };

  build-system = [
    hatchling
  ];

  dependencies = [
    anndata
    array-api-compat
    dtw-python
    gpytorch
    h5py
    mizani
    mudata
    numpy
    packaging
    pandas
    platformdirs
    plotnine
    pyro-ppl
    scikit-learn
    scipy
    session-info2
    statsmodels
    torch
    tqdm
  ];

  pythonImportsCheck = [ "mofaflex" ];

  doCheck = false;

  meta = with lib; {
    description = "Factor Analysis Models";
    homepage = "https://github.com/bioFAM/mofaflex";
    license = licenses.bsd3;
    maintainers = [ ];
  };
}

